azureLogAnalytics.query:
let submitted = toscalar(customEvents | where $__timeFilter(timestamp) | where name == "pwa.payment_submitted" | count);
let failed = toscalar(customEvents | where $__timeFilter(timestamp) | where name == "pwa.payment_failed" | count);
print failure_rate_pct = iff(submitted == 0, 0.0, round(100.0 * failed / submitted, 1))

let completed = toscalar(customEvents | where $__timeFilter(timestamp) | where name == "pwa.payment_completed" | count);
let optins = toscalar(customEvents | where $__timeFilter(timestamp) | where name == "pwa.payment_completed" | where tostring(customDimensions.autopay_opt_in) == "true" | count);
print autopay_opt_in_pct = iff(completed == 0, 0.0, round(100.0 * optins / completed, 1))

let completed = toscalar(customEvents | where $__timeFilter(timestamp) | where name == "pwa.payment_completed" | count);
let optins = toscalar(customEvents | where $__timeFilter(timestamp) | where name == "pwa.payment_completed" | where tostring(customDimensions.paperless_opt_in) == "true" | count);
print paperless_opt_in_pct = iff(completed == 0, 0.0, round(100.0 * optins / completed, 1))
